// Student data and models

class StudentInfo {
  final String name;
  final String code;
  final String status;
  final String department;
  final String level;

  const StudentInfo({
    required this.name,
    required this.code,
    required this.status,
    required this.department,
    required this.level,
  });

  Map<String, String> toMap() => {
    'name': name,
    'code': code,
    'status': status,
    'department': department,
    'level': level,
  };

  static StudentInfo fromMap(Map<String, dynamic> m) => StudentInfo(
    name: (m['name'] ?? '').toString(),
    code: (m['code'] ?? '').toString(),
    status: (m['status'] ?? '').toString(),
    department: (m['department'] ?? '').toString(),
    level: (m['level'] ?? '').toString(),
  );
}

